code = """import json
import re

# Load 2011 results
articles_2011_path = locals()['var_function-call-5001127147893493361']
if isinstance(articles_2011_path, str):
    with open(articles_2011_path, 'r') as f:
        articles_2011 = json.load(f)

# Classification logic
business_keywords = {
    "business", "economy", "economic", "market", "stock", "trade", "finance", "financial", 
    "investment", "investor", "bank", "banking", "profit", "revenue", "sales", "ceo", 
    "management", "corporate", "industry", "inflation", "tax", "rates", "debt", 
    "merger", "acquisition", "deal", "shares", "nasdaq", "dow", "wall street", "money",
    "growth", "recession", "company", "companies", "firm", "firms", "quarter", "earnings",
    "oil", "price", "prices", "consumer", "spending", "budget", "deficit", "currency",
    "dollar", "euro", "yen", "jobs", "unemployment", "labor", "workforce", "retail",
    "fed", "federal reserve", "interest", "loan", "mortgage", "credit", "crisis", "bailout",
    "imf", "wto", "treasury", "bond", "futures", "commodity", "dividend", "ipo"
}

def is_business(title, desc):
    text = (title + " " + desc).lower()
    text = re.sub(r'[^\w\s]', ' ', text)
    words = set(text.split())
    if len(words.intersection(business_keywords)) > 0:
        return True
    return False

count_2011 = 0
for art in articles_2011:
    if is_business(art.get('title', ''), art.get('description', '')):
        count_2011 += 1

# Update results file
with open('results.json', 'r') as f:
    results = json.load(f)

results['2011'] = count_2011

with open('results.json', 'w') as f:
    json.dump(results, f)

# Generate Query for 2012
file_path_meta = locals()['var_function-call-5463793062581898541']
with open(file_path_meta, 'r') as f:
    metadata_list = json.load(f)

ids_2012 = [int(item['article_id']) for item in metadata_list if item['publication_date'].startswith('2012')]
query_2012 = {
    "collection": "articles",
    "filter": {"article_id": {"$in": ids_2012}},
    "limit": 5000
}

print("__RESULT__:")
print(json.dumps(query_2012))"""

